ed:Connect(function(v626) if ((v626.UserInputType==Enum.UserInputType.MouseMovement) or (v626.UserInputType==Enum.UserInputType.Touch)) then if ((662<=972) and v424) then local v951=math.clamp((v626.Position.X-v413.AbsolutePosition.X)/v413.AbsoluteSize.X ,0,1);v418.Position=UDim2.new(v951, -10,0.5, -10);v86.ImageTransparency=v951;end if ((4370==4370) and v38) then local v954=math.clamp((v626.Position.X-v353.AbsolutePosition.X)/v353.AbsoluteSize.X ,0,1);v358.Size=UDim2.new(v954,0,1,0);local v956=math.floor(v954 * 200 );if ((v956<10) or (4762<=861)) then v956=10;end v39=v956;v345.Text="Kecepatan Fly: "   .. v39 ;end end end);local v425=Instance.new("ScrollingFrame",v133);v425.Size=UDim2.new(1,0,1,0);v425.BackgroundTransparency=1;v425.ScrollBarThickness=4;v425.CanvasSize=UDim2.new(0,0,0,900);local v430=Instance.new("TextLabel",v425);v430.Size=UDim2.new(0.92,0,1,0);v430.Position=UDim2.new(0.04,0,0.02,0);v430.BackgroundTransparency=1;v430.Text=utf8.char(129399)   .. " BUKU PANDUAN MUTLAK: PHANTOMWALK PRO V2.8 \n\n"   .. "Developed by: EL KAPITAN ~ XXV\n\n"   .. utf8.char(128194)   .. " BAB 1: MEMUNCULKAN PANEL KONTROL\n"   .. "Saat pertama kali di-execute, lu bakal lihat UI utama. Di tab ["   .. utf8.char(127918)   .. " Main Control], lu bakal nemuin dua tombol penting:\n\n"   .. "Show REC Panel (Merah): Klik ini buat memunculkan panel Perekam (untuk bikin jalur). Klik lagi untuk menyembunyikannya jika sudah selesai digunakan.\n\n"   .. "Show PLAY Panel (Hijau): Klik ini buat memunculkan panel Player (untuk memutar jalur). Klik lagi untuk menyembunyikannya jika sudah selesai digunakan.\n"   .. "(Tips: Pindahkan panel-panel ini ke area layar yang gak ganggu jari lu pas main).\n\n"   .. utf8.char(128308)   .. " BAB 2: CARA MEREKAM JALUR (RECORDING 101)\n"   .. "Ini adalah fitur utama untuk membuat karakter lu jalan sendiri melewati rintangan/obby.\n"   .. "Buka REC Panel.\n"   .. "Berdiri di titik awal (start). \n\n"   .. "Klik tombol ["   .. utf8.char(128308)   .. ' REC]. Status di layar akan berubah jadi \"Merekam\".\n'   .. "Silakan jalan lewatin obby seperti biasa. Semua gerakan lu (lompat, diam, jalan pelan, shift-lock) direkam secara 100% real-time.\n\n"   .. "JATUH ATAU KEPLESET? JANGAN PANIK! Gak usah tekan Stop. Langsung klik tombol ["   .. utf8.char(9194)   .. " UNDO]. Karakter lu bakal otomatis di-rewind (mundur) ke beberapa rintangan sebelumnya. Setelah karakter berhenti mundur, langsung lanjutin jalan lagi!\n"   .. "Kalau udah sampai di titik akhir yang lu mau, klik tombol ["   .. utf8.char(9209)   .. " STOP].\n\n"   .. utf8.char(128190)   .. " BAB 3: CARA MENYIMPAN & MENYAMBUNG JALUR\n"   .. "Biar capek lu gak sia-sia, jalur harus di-save!\n\n"   .. "Di REC Panel, klik kotak TextBox dan ketik nama jalur lu.\n"   .. "(SANGAT DISARANKAN pakai angka: 1, 2, 3, dst. Nanti dijelaskan alasannya).\n\n"   .. "Klik tombol ["   .. utf8.char(128190)   .. " SAVE]. Selesai! Jalur lu udah aman tersimpan di database HP lu biarpun lu keluar dari game.\n\n"   .. "["   .. utf8.char(127937)   .. ' TP END]: Kalau lu baru selesai nyimpan jalur \"1\", dan mau lanjut ngerakam jalur \"2\", klik tombol TP END. Karakter lu bakal otomatis diteleport dengan presisi ke titik ujung jalur \"1\" tadi. Tinggal klik REC lagi buat nyambung!\n\n'   .. utf8.char(128260)   .. ' BAB 4: SISTEM \"AUTO MERGE\" (PENGGABUNGAN OTOMATIS)\n\n'   .. "Punya banyak jalur terpisah (1, 2, 3, 4, 5) dan capek nge-play satu-satu?\n\n"   .. "Buka Tab ["   .. utf8.char(128193)   .. " Path Manager].\n"   .. "Klik tombol ["   .. utf8.char(128279)   .. " Auto Merge Path Angka].\n"   .. "BOOM! Script akan menyatukan path 1, 2, 3, dst secara otomatis menjadi satu jalur panjang tanpa jeda! (Pastikan nama path lu pakai angka biar sistem bisa ngurutinnya).\n\n"   .. utf8.char(9654)   .. " BAB 5: CARA MEMUTAR JALUR (PLAY & SPEED)\n"   .. "Udah punya jalur? Saatnya rebahan dan biarin script yang kerja.\n\n"   .. "Buka Tab ["   .. utf8.char(128193)   .. " Path Manager], cari nama path lu, lalu klik Pilih (Load).\n"   .. "Tentukan kecepatan di Tab ["   .. utf8.char(9889)   .. " Speed Autowalk]:\n\n"   .. "NORMAL: (Sangat Disarankan). Kecepatan kaki dan pergerakan badan 100% persis seperti saat lu merekam. Bebas mau sambil pegang Coil atau nggak, script ini punya rekaman DNA kecepatan lu di masa lalu!\n\n"   .. "SUPER: Mode ngebut tanpa kompromi.\n"   .. "Buka PLAY Panel, lalu klik ["   .. utf8.char(9654)   .. " PLAY]. Karakter lu bakal jalan sendiri!\n\n"   .. "FORCE STOP: Kalau karakter lu tiba-tiba nyangkut karena ada orang rese ngehalangin jalan, langsung Geser Analog HP Lu! Script akan otomatis membatalkan autowalk secara paksa.\n"   .. "Klik [EL MUNDUR] kalau mau gaya jalan Mundur!\n\n"   .. utf8.char(9889)   .. " BAB 6: FITUR LAINNYA\n"   .. "Buka Tab ["   .. utf8.char(9889)   .. " Fitur] untuk menikmati sihir developer:\n"   .. utf8.char(127917)   .. " Copy Avatar (CS): Masukkan username target di map yang sama, klik COPY AVATAR. Lu bakal langsung nge- clone wujud mereka!\n\n"   .. utf8.char(128640)   .. " Teleport Hub: Berdiri di spot/cp yang lu mau, ketik nama di textbox, lalu klik Mark. Lu bisa balik lagi ke spot/cp itu kapan aja dengan klik GO. Ada fitur Auto Loop Teleport juga buat farming otomatis!\n\n"   .. utf8.char(128065)   .. " Path Visualizer (ESP): Nyalakan ini untuk melihat garis neon yang menunjukkan ke mana arah path rekaman lu membentang. Warnanya bisa diganti sesuka hati!\n\n"   .. utf8.char(129666)   .. " Sistem Parasut: Jatuh dari tempat tinggi? Nyalakan ini biar karakter lu melayang turun pelan-pelan tanpa damage.\n\n"   .. utf8.char(9992)   .. " Fly Mode: Terbang menembus map dengan slider kontrol kecepatan yang bisa disesuaikan (10 - 200 Speed)." ;v430.TextColor3=v49;v430.Font=Enum.Font.Gotham;v430.TextSize=10;v430.TextWrapped=true;v430.TextXAlignment=Enum.TextXAlignment.Left;v430.TextYAlignment=Enum.TextYAlignment.Top;local v442=Instance.new("TextLabel",v134);v442.Size=UDim2.new(0.9,0,0.8,0);v442.Position=UDim2.new(0.05,0,0.05,0);v442.BackgroundTransparency=1;v442.Text="PhantomWalk Pro V2.8 FINAL\n\n"   .. " XXV ~ EL KAPITAN "   .. utf8.char(128572) ;v442.TextColor3=v49;v442.Font=Enum.Font.Gotham;v442.TextSize=12;v442.TextWrapped=true;v442.TextXAlignment=Enum.TextXAlignment.Center;v442.TextYAlignment=Enum.TextYAlignment.Center;v1.RenderStepped:Connect(function() if v52.Visible then v64.Offset=Vector2.new(0,((tick() * 2)%1) -0.5 );v61.Transparency=math.random(10,40)/100 ;end end);local v455=0;function drawPathLines() v455=v455 + 1 ;local v627=v455;if (v6:FindFirstChild("MacroPathLines") or (1412==4264)) then v6:FindFirstChild("MacroPathLines"):Destroy();end if ( not v31 or ( #v20==0)) then return;end local v628=Instance.new("Folder");v628.Name="MacroPathLines";v628.Parent=v6;task.spawn(function() local v718=15;local v719=0;for v774=1, #v20-v718 ,v718 do if ((v627~=v455) or (3168<2153)) then return;end local v775=v20[v774].Pos;local v776=v20[v774 + v718 ].Pos;local v777=(v776-v775).Magnitude;if ((v777>0.1) or (4976<1332)) then local v958=Instance.new("Part");v958.Size=Vector3.new(0.15,0.15,v777);v958.CFrame=CFrame.lookAt(v775,v776) * CFrame.new(0,0, -v777/2 ) ;v958.Anchored=true;v958.CanCollide=false;v958.CanQuery=false;v958.CastShadow=false;v958.Material=Enum.Material.Neon;v958.Color=v32;v958.Transparency=0.4;v958.Parent=v628;v719=v719 + 1 ;if ((v719%25)~=0) then else v1.Heartbeat:Wait();end end end end);end
